import React, { useState } from 'react';
import { Menu, X } from 'lucide-react';

const Navbar = () => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  const toggleMobileMenu = () => {
    setIsMobileMenuOpen(!isMobileMenuOpen);
  };

  return (
    <nav className="relative z-10 bg-gray-900 py-4 shadow-lg border-b border-gray-800">
      <div className="container mx-auto px-6 flex items-center justify-between">
        <div className="flex items-center">
          <a href="/" className="text-2xl font-bold text-zinc-200 hover:text-zinc-100">
            NexusFlow
          </a>
        </div>

        {/* Desktop Navigation */}
        <div className="hidden md:flex space-x-8 items-center">
          <a href="#features" className="text-zinc-300 hover:text-zinc-100 transition-colors duration-300">Features</a>
          <a href="#testimonials" className="text-zinc-300 hover:text-zinc-100 transition-colors duration-300">Testimonials</a>
          <a href="#pricing" className="text-zinc-300 hover:text-zinc-100 transition-colors duration-300">Pricing</a>
          <a href="#cta" className="text-zinc-300 hover:text-zinc-100 transition-colors duration-300">Contact</a>
        </div>

        {/* Mobile Menu Button */}
        <div className="md:hidden">
          <button onClick={toggleMobileMenu} className="text-zinc-300 hover:text-zinc-100 focus:outline-none focus:text-zinc-100">
            {isMobileMenuOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
          </button>
        </div>
      </div>

      {/* Mobile Menu */}
      {isMobileMenuOpen && (
        <div className="md:hidden bg-gray-800 mt-4 py-4 px-6 space-y-3">
          <a href="#features" className="block text-zinc-300 hover:text-zinc-100 transition-colors duration-300">Features</a>
          <a href="#testimonials" className="block text-zinc-300 hover:text-zinc-100 transition-colors duration-300">Testimonials</a>
          <a href="#pricing" className="block text-zinc-300 hover:text-zinc-100 transition-colors duration-300">Pricing</a>
          <a href="#cta" className="block text-zinc-300 hover:text-zinc-100 transition-colors duration-300">Contact</a>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

