import React, { useState } from 'react';
import { ChevronLeft, ChevronRight } from 'lucide-react';

const TestimonialCarousel = () => {
  const testimonials = [
    {
      quote: "NexusFlow has completely transformed how we manage our projects. The automation capabilities are outstanding!",
      author: "Alice Johnson",
      title: "Project Manager, TechCorp",
      image: "https://via.placeholder.com/60/909090/FFFFFF?text=AJ",
    },
    {
      quote: "The ease of use and the intuitive interface make it a joy to work with. Highly recommended.",
      author: "Bob Williams",
      title: "Lead Developer, Innovate Solutions",
      image: "https://via.placeholder.com/60/909090/FFFFFF?text=BW",
    },
    {
      quote: "Customer support is top-notch. They helped us integrate NexusFlow seamlessly into our existing workflow.",
      author: "Charlie Brown",
      title: "Operations Director, Global Enterprises",
      image: "https://via.placeholder.com/60/909090/FFFFFF?text=CB",
    },
  ];

  const [currentIndex, setCurrentIndex] = useState(0);

  const goToPrevious = () => {
    const isFirstSlide = currentIndex === 0;
    const newIndex = isFirstSlide ? testimonials.length - 1 : currentIndex - 1;
    setCurrentIndex(newIndex);
  };

  const goToNext = () => {
    const isLastSlide = currentIndex === testimonials.length - 1;
    const newIndex = isLastSlide ? 0 : currentIndex + 1;
    setCurrentIndex(newIndex);
  };

  return (
    <section id="testimonials" className="py-24 bg-gray-800 text-white">
      <div className="container mx-auto px-6">
        <h2 className="text-4xl font-bold text-center mb-16 text-white">What Our Clients Say</h2>
        <div className="relative max-w-3xl mx-auto text-center">
          <button
            onClick={goToPrevious}
            className="absolute left-0 top-1/2 -translate-y-1/2 bg-gray-700 hover:bg-gray-600 p-3 rounded-full focus:outline-none focus:bg-gray-500 transition-colors duration-300"
            aria-label="Previous testimonial"
          >
            <ChevronLeft className="w-8 h-8" />
          </button>
          <div className="px-8 md:px-16">
            <p className="text-2xl italic font-light mb-8 leading-relaxed">
              "{testimonials[currentIndex].quote}"
            </p>
            <div className="flex flex-col items-center">
              <img
                src={testimonials[currentIndex].image}
                alt={testimonials[currentIndex].author}
                className="w-16 h-16 rounded-full mb-4 border-2 border-zinc-500"
              />
              <h4 className="text-xl font-semibold text-zinc-200">{testimonials[currentIndex].author}</h4>
              <p className="text-zinc-400">{testimonials[currentIndex].title}</p>
            </div>
          </div>
          <button
            onClick={goToNext}
            className="absolute right-0 top-1/2 -translate-y-1/2 bg-gray-700 hover:bg-gray-600 p-3 rounded-full focus:outline-none focus:bg-gray-500 transition-colors duration-300"
            aria-label="Next testimonial"
          >
            <ChevronRight className="w-8 h-8" />
          </button>
        </div>
        <div className="flex justify-center space-x-4 mt-12">
          {testimonials.map((_, index) => (
            <button
              key={index}
              onClick={() => setCurrentIndex(index)}
              className={`w-3 h-3 rounded-full transition-colors duration-300 ${
                index === currentIndex ? 'bg-zinc-200' : 'bg-gray-600 hover:bg-gray-500'
              }`}
              aria-label={`Go to testimonial ${index + 1}`}
            ></button>
          ))}
        </div>
      </div>
    </section>
  );
};

export default TestimonialCarousel;

