import React, { useState } from 'react';

const PricingPlan = () => {
  const [selectedPlan, setSelectedPlan] = useState('pro');

  const plans = [
    {
      name: 'Basic',
      price: '$19',
      features: [
        '10 Projects',
        '5 Users',
        'Basic Support',
        'Limited Integrations',
      ],
      isFeatured: false,
      id: 'basic',
    },
    {
      name: 'Pro',
      price: '$49',
      features: [
        'Unlimited Projects',
        '15 Users',
        'Priority Support',
        'All Integrations',
        'Advanced Analytics',
      ],
      isFeatured: true,
      id: 'pro',
    },
    {
      name: 'Enterprise',
      price: '$99',
      features: [
        'Unlimited Projects',
        'Unlimited Users',
        'Dedicated Support',
        'All Integrations',
        'Custom Features',
        'SSO Integration',
      ],
      isFeatured: false,
      id: 'enterprise',
    },
  ];

  return (
    <section id="pricing" className="py-24 bg-gray-900 text-white">
      <div className="container mx-auto px-6">
        <h2 className="text-4xl font-bold text-center mb-16 text-white">Flexible Pricing Plans</h2>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-12">
          {plans.map((plan) => (
            <div
              key={plan.id}
              className={`bg-gray-800 p-8 rounded-lg shadow-lg border border-gray-700 transition-all duration-300
                ${plan.isFeatured ? 'border-zinc-600 scale-105 shadow-xl' : ''}
                ${selectedPlan === plan.id ? 'border-zinc-500 ring-2 ring-zinc-500' : ''}`}
              onClick={() => setSelectedPlan(plan.id)}
            >
              <div className="flex justify-between items-center mb-6">
                <h3 className={`text-3xl font-bold ${plan.isFeatured ? 'text-zinc-100' : 'text-zinc-200'}`}>
                  {plan.name}
                </h3>
                <span className={`text-4xl font-bold ${plan.isFeatured ? 'text-white' : 'text-zinc-200'}`}>
                  {plan.price}
                </span>
              </div>
              <ul className="space-y-4 mb-8 text-zinc-300">
                {plan.features.map((feature, index) => (
                  <li key={index} className="flex items-center">
                    <svg className="w-5 h-5 mr-3 text-zinc-400 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"></path></svg>
                    <span>{feature}</span>
                  </li>
                ))}
              </ul>
              <button
                className={`w-full py-3 font-semibold rounded-md transition-colors duration-300
                  ${plan.isFeatured
                    ? 'bg-zinc-200 text-gray-900 hover:bg-white'
                    : selectedPlan === plan.id
                      ? 'bg-zinc-700 hover:bg-zinc-600 text-white'
                      : 'bg-gray-700 hover:bg-gray-600 text-zinc-300'
                  }`}
              >
                {plan.id === 'enterprise' ? 'Contact Sales' : 'Choose Plan'}
              </button>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default PricingPlan;

