h1, h2, h3, h4, h5, h6 {
  font-family: 'DM Sans', sans-serif;
}

/* Custom animation for gradient background */
@keyframes gradient-pulse {
  0% {
    transform: scale(1);
    opacity: 0.3;
  }
  50% {
    transform: scale(1.1);
    opacity: 0.5;
  }
  100% {
    transform: scale(1);
    opacity: 0.3;
  }
}

.animate-gradient-pulse {
  animation: gradient-pulse 6s infinite ease-in-out;
}

export default {};

